#!/usr/bin/env python3
import sys
from datetime import datetime

CERT_PATH = "/app/ssl/server.crt"


def load_cert():
    try:
        from cryptography import x509
        from cryptography.hazmat.backends import default_backend
        with open(CERT_PATH, "rb") as f:
            return x509.load_pem_x509_certificate(f.read(), default_backend())
    except ImportError:
        return None


def get_details_cryptography(cert):
    from cryptography.x509.oid import NameOID
    cn = cert.subject.get_attributes_for_oid(NameOID.COMMON_NAME)[0].value
    try:
        expire = cert.not_valid_after_utc
    except AttributeError:
        expire = cert.not_valid_after
    return cn, expire.strftime("%Y-%m-%d")


def get_details_openssl():
    import subprocess
    cn = None
    subj = subprocess.run(
        ["openssl", "x509", "-in", CERT_PATH, "-noout", "-subject"],
        capture_output=True, text=True, check=True).stdout
    for part in subj.replace("/", ",").split(","):
        part = part.strip()
        if part.startswith("CN"):
            cn = part.split("=", 1)[1].strip()
    enddate = subprocess.run(
        ["openssl", "x509", "-in", CERT_PATH, "-noout", "-enddate"],
        capture_output=True, text=True, check=True).stdout.strip()
    enddate = enddate.split("=", 1)[1].strip()
    dt = datetime.strptime(enddate, "%b %d %H:%M:%S %Y %Z")
    return cn, dt.strftime("%Y-%m-%d")


def main():
    import os
    if not os.path.exists(CERT_PATH):
        print("Certificate file not found:", CERT_PATH)
        sys.exit(1)

    cert = load_cert()
    if cert is not None:
        cn, expire = get_details_cryptography(cert)
    else:
        cn, expire = get_details_openssl()

    print("Certificate loaded successfully")
    print("Common Name:", cn)
    print("Expiration Date:", expire)
    print("Certificate verification successful")


if __name__ == "__main__":
    main()
